#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 505;
const int K = 5e3+5;
struct Trie{int fail,son[30];}t[N];
int n,Cnt,val[N],tot,Now,lst[N*K];
pii Fa[N];
string s[N];queue<pii> q;
bool vis[N][K];char hh[N*K];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void BuildTrie(string str,int id){
    int now=0;
    for(char c:str){
        if(!t[now].son[c-'A'])
            t[now].son[c-'A']=(++Cnt);
        now=t[now].son[c-'A'];
    }val[now]|=(1<<id-1);return;
}
void CountFail(){
    queue<int> q;
    while(!q.empty())q.pop();
    t[0].fail=0;
    for(int i=0;i<26;i++)if(t[0].son[i])
        t[t[0].son[i]].fail=0,q.push(t[0].son[i]);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=0;i<26;i++){
            if(t[u].son[i])
                t[t[u].son[i]].fail=t[t[u].fail].son[i],
                val[t[u].son[i]]|=val[t[t[u].fail].son[i]],
                q.push(t[u].son[i]);
            else t[u].son[i]=t[t[u].fail].son[i];
        }
    }return;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)
        {cin>>s[i];BuildTrie(s[i],i);}
    CountFail();
    q.push({0,0});vis[0][0]=1;
    while(!q.empty()){
        auto [u,w]=q.front();q.pop();
        if(w==(1<<n)-1){
            stack<char> tmp;
            while(!tmp.empty())tmp.pop();
            while(Now)tmp.push(hh[Now]),Now=lst[Now];
            while(!tmp.empty())
                {cout<<tmp.top();tmp.pop();}
            cout<<"\n";break;
        }for(int i=0;i<26;i++){
            int nxt=t[u].son[i];
            if(!nxt||vis[nxt][w|val[nxt]])continue;
            vis[nxt][w|val[nxt]]=1;
            q.push({nxt,w|val[nxt]});
            lst[++tot]=Now,hh[tot]=(char)(i+'A');
        }Now++;
    }
    return 0;
}
